frame_eqs:
wave_a = bass_att;

wave_r += sin(time*3);
wave_g += sin(time/2);
wave_b += sin(time/4);

zoom=zoom+(bass_att-1)*0.1;

q1 = tilechng = if(above(bass, 2), int(rand(5)), tilechng);

wave_0_per_point:
tscale=.45+(bass*.02);
trot=3;
a=above(sample,0);

tp1x=.5+(cos(3.1415*0+(time*trot))*tscale*.75);
tp1y=.5+(sin(3.1415*0+(time*trot))*tscale);

tp2x=.5+(cos(3.1415*.6667+(time*trot))*tscale*.75);
tp2y=.5+(sin(3.1415*.6667+(time*trot))*tscale*sin(time)); //spin

tp3x=.5+(cos(3.1415*1.3333+(time*trot))*tscale*.75);
tp3y=.5+(sin(3.1415*1.3333+(time*trot))*tscale*sin(time)); //spin


//draw via random walk
tri_point=int(rand(3));

//point 1
t_x=t_x+(equal(tri_point,0)*(tp1x-t_x)*.5);
t_y=t_y+(equal(tri_point,0)*(tp1y-t_y)*.5);

//point 2
t_x=t_x+(equal(tri_point,1)*(tp2x-t_x)*.5);
t_y=t_y+(equal(tri_point,1)*(tp2y-t_y)*.5);

//point 3
t_x=t_x+(equal(tri_point,2)*(tp3x-t_x)*.5);
t_y=t_y+(equal(tri_point,2)*(tp3y-t_y)*.5);

x=t_x;
y=t_y;

r += sin(time/2);
g += cos(time*3);
b += cos(time*4);

